    "wobble",
    "dropout",
    "hesitate",
    "overshoot",
    "repeat",
    "drift",
    "bleed",
    "bleedPasses",
    "bleedSpread",
    "bleedCluster",
    "rubout",
    "fray",
    "pressure",
    "fill",
    "hatchSpacing",
    "hatchAngle",
    "glyphJitter",
    "segmentLength",
    "seed"
