    { dx: -110, dy: -80, w: 250, h: 168, weight: 0.5,  dropout: 0.04, pressure: 0.1  },
    { dx:   76, dy: -52, w: 262, h: 140, weight: 0.42, dropout: 0.06, pressure: 0.05 },
    { dx:  210, dy:   8, w: 150, h: 90,  weight: 0.3,  dropout: 0.1,  pressure: 0.04 }
